1914→        NDS_VEC_VREDSUM_VS(NDS_VEC_V0,  NDS_VEC_V15, NDS_VEC_V31);  //ch3*pix3
1915→
1916→        // Pack 4 scalars into VL=4 vectors via vslideup
1917→        // pix0: v16 = [ch0, ch1, ch2, ch3]
1918→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1919→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
1920→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
1921→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V25, 1);
1922→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V29, 1);
