1850→            NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
1851→            NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
1852→            NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
1853→            NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);
1854→
1855→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1856→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_b0);
1857→            NDS_VEC_VLE8_V(NDS_VEC_V21, ptr_b1);
1858→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_b2);
1859→            NDS_VEC_VLE8_V(NDS_VEC_V23, ptr_b3);
1860→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1861→            NDS_VEC_VLE8_V(NDS_VEC_V17, ptr_a1);
1862→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_a2);
1863→            NDS_VEC_VLE8_V(NDS_VEC_V19, ptr_a3);
1864→            ptr_a0 += vl;
1865→            ptr_a1 += vl;
1866→            ptr_a2 += vl;
1867→            ptr_a3 += vl;
1868→
1869→            vl = (vl + 3) >> 2;
1870→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1871→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
1872→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
1873→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
1874→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
1875→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
1876→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
1877→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
1878→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
1879→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
1880→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
1881→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
1882→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
1883→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
1884→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
1885→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
1886→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
1887→        }
1888→
1889→        // === Reduction epilogue: 16 vredsum → pack to VL=4 → requantize ===
1890→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1891→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
1892→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1893→
1894→        // Reduce 16 accumulators to scalars in element [0]
1895→        // pix0: ch0→v16[0], ch1→v17[0], ch2→v18[0], ch3→v19[0]
1896→        NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0
1897→        NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0
1898→        NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0
1899→        NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0
1900→        // pix1: ch0→v20[0], ch1→v21[0], ch2→v22[0], ch3→v23[0]
1901→        NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V1,  NDS_VEC_V31);  //ch0*pix1
1902→        NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V5,  NDS_VEC_V31);  //ch1*pix1
1903→        NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V9,  NDS_VEC_V31);  //ch2*pix1
1904→        NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V13, NDS_VEC_V31);  //ch3*pix1
1905→        // pix2: ch0→v24[0], ch1→v25[0], ch2→v26[0], ch3→v27[0]
1906→        NDS_VEC_VREDSUM_VS(NDS_VEC_V24, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix2
1907→        NDS_VEC_VREDSUM_VS(NDS_VEC_V25, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix2
1908→        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix2
1909→        NDS_VEC_VREDSUM_VS(NDS_VEC_V27, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix2
1910→        // pix3: ch0→v28[0], ch1→v29[0], ch2→v30[0], ch3→v0[0] (reuse v0, done with accumulators)
1911→        NDS_VEC_VREDSUM_VS(NDS_VEC_V28, NDS_VEC_V3,  NDS_VEC_V31);  //ch0*pix3
1912→        NDS_VEC_VREDSUM_VS(NDS_VEC_V29, NDS_VEC_V7,  NDS_VEC_V31);  //ch1*pix3
1913→        NDS_VEC_VREDSUM_VS(NDS_VEC_V30, NDS_VEC_V11, NDS_VEC_V31);  //ch2*pix3
1914→        NDS_VEC_VREDSUM_VS(NDS_VEC_V0,  NDS_VEC_V15, NDS_VEC_V31);  //ch3*pix3
1915→
1916→        // Pack 4 scalars into VL=4 vectors via vslideup
1917→        // pix0: v16 = [ch0, ch1, ch2, ch3]
1918→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1919→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
1920→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
1921→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V25, 1);
1922→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V29, 1);
1923→        NDS_VEC_VSETVLI(vl, 3, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1924→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
1925→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
1926→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V26, 2);
1927→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V30, 2);
1928→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1929→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
1930→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);
1931→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V27, 3);
1932→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V0,  3);
1933→
1934→        // v16=pix0, v20=pix1, v24=pix2, v28=pix3 — each [ch0,ch1,ch2,ch3]
1935→
1936→        //add extra contribution back
1937→        NDS_VEC_VLE32_V(NDS_VEC_V1, contri_buf);
1938→        contri_buf += vl;
1939→        NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V1);
1940→        NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V1);
1941→        NDS_VEC_VADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V1);
1942→        NDS_VEC_VADD_VV(NDS_VEC_V28, NDS_VEC_V28, NDS_VEC_V1);
1943→
1944→        //===== Quantize down =====
1945→        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
1946→        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
1947→        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
1948→
1949→        NDS_VEC_VWMUL_VV(NDS_VEC_V4,  NDS_VEC_V16, NDS_VEC_V3);
1950→        NDS_VEC_VWMUL_VV(NDS_VEC_V6,  NDS_VEC_V20, NDS_VEC_V3);
1951→        NDS_VEC_VWMUL_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V3);
1952→        NDS_VEC_VWMUL_VV(NDS_VEC_V10, NDS_VEC_V28, NDS_VEC_V3);
1953→        NDS_VEC_VNSRA_WV(NDS_VEC_V4,  NDS_VEC_V4,  NDS_VEC_V2);
1954→        NDS_VEC_VNSRA_WV(NDS_VEC_V6,  NDS_VEC_V6,  NDS_VEC_V2);
1955→        NDS_VEC_VNSRA_WV(NDS_VEC_V8,  NDS_VEC_V8,  NDS_VEC_V2);
1956→        NDS_VEC_VNSRA_WV(NDS_VEC_V10, NDS_VEC_V10, NDS_VEC_V2);
1957→        NDS_VEC_VSSRA_VI(NDS_VEC_V4,  NDS_VEC_V4,  1);
1958→        NDS_VEC_VSSRA_VI(NDS_VEC_V6,  NDS_VEC_V6,  1);
1959→        NDS_VEC_VSSRA_VI(NDS_VEC_V8,  NDS_VEC_V8,  1);
1960→        NDS_VEC_VSSRA_VI(NDS_VEC_V10, NDS_VEC_V10, 1);
1961→
1962→        // Add offset
1963→        NDS_VEC_VADD_VX(NDS_VEC_V4,  NDS_VEC_V4,  out_offset);
1964→        NDS_VEC_VADD_VX(NDS_VEC_V6,  NDS_VEC_V6,  out_offset);
1965→        NDS_VEC_VADD_VX(NDS_VEC_V8,  NDS_VEC_V8,  out_offset);
1966→        NDS_VEC_VADD_VX(NDS_VEC_V10, NDS_VEC_V10, out_offset);
1967→
1968→        // Clamp the result
1969→        NDS_VEC_VMAX_VX(NDS_VEC_V4,  NDS_VEC_V4,  act_min);
1970→        NDS_VEC_VMIN_VX(NDS_VEC_V4,  NDS_VEC_V4,  act_max);
1971→        NDS_VEC_VMAX_VX(NDS_VEC_V6,  NDS_VEC_V6,  act_min);
1972→        NDS_VEC_VMIN_VX(NDS_VEC_V6,  NDS_VEC_V6,  act_max);
1973→        NDS_VEC_VMAX_VX(NDS_VEC_V8,  NDS_VEC_V8,  act_min);
1974→        NDS_VEC_VMIN_VX(NDS_VEC_V8,  NDS_VEC_V8,  act_max);
1975→        NDS_VEC_VMAX_VX(NDS_VEC_V10, NDS_VEC_V10, act_min);
1976→        NDS_VEC_VMIN_VX(NDS_VEC_V10, NDS_VEC_V10, act_max);
1977→
1978→        //narrowing and store the results
1979→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
1980→        NDS_VEC_VNSRA_VI(NDS_VEC_V4,  NDS_VEC_V4,  0);
1981→        NDS_VEC_VNSRA_VI(NDS_VEC_V6,  NDS_VEC_V6,  0);
1982→        NDS_VEC_VNSRA_VI(NDS_VEC_V8,  NDS_VEC_V8,  0);
1983→        NDS_VEC_VNSRA_VI(NDS_VEC_V10, NDS_VEC_V10, 0);
1984→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1985→        NDS_VEC_VNSRA_VI(NDS_VEC_V4,  NDS_VEC_V4,  0);
1986→        NDS_VEC_VNSRA_VI(NDS_VEC_V6,  NDS_VEC_V6,  0);
1987→        NDS_VEC_VNSRA_VI(NDS_VEC_V8,  NDS_VEC_V8,  0);
1988→        NDS_VEC_VNSRA_VI(NDS_VEC_V10, NDS_VEC_V10, 0);
1989→        NDS_VEC_VSE8_V(NDS_VEC_V4,  out_0);
1990→        NDS_VEC_VSE8_V(NDS_VEC_V6,  out_1);
1991→        NDS_VEC_VSE8_V(NDS_VEC_V8,  out_2);
1992→        NDS_VEC_VSE8_V(NDS_VEC_V10, out_3);
1993→        out_0 += 4;
1994→        out_1 += 4;
1995→        out_2 += 4;
1996→        out_3 += 4;
1997→        out_scale += 4;
1998→        out_shift += 4;
1999→
2000→        ptr_a0 += 3 * (long)num_col_a;  // skip past channels 1,2,3
2001→    }
2002→
2003→    // === Handle remaining 2 channels (if out_tensor_ch % 4 >= 2) ===
2004→    if ((out_tensor_ch & 0x3) >= 2)
2005→    {
2006→        const int8_t *ptr_b0 = input_b;
2007→        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
2008→        const int8_t *ptr_b2 = ptr_b1 + num_col_a;
2009→        const int8_t *ptr_b3 = ptr_b2 + num_col_a;
2010→        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
2011→
2012→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2013→        NDS_VEC_VAND_VI(NDS_VEC_V0,  NDS_VEC_V0,  0x0);
2014→        NDS_VEC_VAND_VI(NDS_VEC_V1,  NDS_VEC_V1,  0x0);
2015→        NDS_VEC_VAND_VI(NDS_VEC_V2,  NDS_VEC_V2,  0x0);
2016→        NDS_VEC_VAND_VI(NDS_VEC_V3,  NDS_VEC_V3,  0x0);
2017→        NDS_VEC_VAND_VI(NDS_VEC_V4,  NDS_VEC_V4,  0x0);
2018→        NDS_VEC_VAND_VI(NDS_VEC_V5,  NDS_VEC_V5,  0x0);
2019→        NDS_VEC_VAND_VI(NDS_VEC_V6,  NDS_VEC_V6,  0x0);
2020→        NDS_VEC_VAND_VI(NDS_VEC_V7,  NDS_VEC_V7,  0x0);
2021→
2022→        long col_count = num_col_a;
2023→        while(col_count >= maxvl_per_loop)
2024→        {
2025→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
2026→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
2027→            NDS_VEC_VLE8_V(NDS_VEC_V17, ptr_a1);

