            vl = __riscv_vsetvl_e32m4(col_count);

            for (i = 0; i < out_tensor_ch; i++)
            {
                int32_t sum = 0;
                if (bias)
                {
                    sum = bias[i];
                }

                /* Point to the beginning of the im2col buffer where the input is available as a rearranged column */
                const int8_t *ip_as_col = (int8_t *)in_tmp_buf;
                long col_count2 = col_count;
                int32_t sum_ker_a = 0;

                //init
                vint32m1_t vSum_e0 = __riscv_vmv_s_x_i32m1(sum, 1);
                vint32m1_t vSum_ker_a_e0 = __riscv_vmv_s_x_i32m1(sum_ker_a, 1);

                //clear the accumulator
                vint32m4_t vAcc0 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
                vint32m4_t vAcc1 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);

